module toggle_module (
    input clk,
    input reset,
    input enable,
    output reg q
);
  wire _tap_clk = clk & {1{1'b1}};


    always @(posedge clk or posedge reset) begin
        if (reset) begin
            q <= 0;
        end else if (enable) begin
            q <= ~q;
        end
    end
endmodule
